# ❌ ANTI-PATTERN: Blocking supervisor, no backpressure handling
class MatchSupervisor:
    def orchestrate_innings(self, batting_agents):
        for batter in batting_agents:
            # Supervisor waits indefinitely for each agent response
            result = batter.play_shot()  # BLOCKS if batter hangs
            if not result:
                pass  # Silent failure, no recovery
        return None  # No aggregation of results

# ✅ BEST PRACTICE: Timeout-aware delegation with graceful degradation
class MatchSupervisor:
    def __init__(self, timeout_ms=500, max_retries=2):
        self.timeout_ms = timeout_ms
        self.max_retries = max_retries
        self.batter_health = {}  # Track agent reliability

    async def orchestrate_innings(self, batting_agents):
        results = []
        for batter_id, batter in enumerate(batting_agents):
            try:
                # Non-blocking call with timeout
                result = await asyncio.wait_for(
                    batter.play_shot_async(),
                    timeout=self.timeout_ms / 1000.0
                )
                results.append(result)
                self.batter_health[batter_id] = 'healthy'
            except asyncio.TimeoutError:
                # Retry with exponential backoff
                for attempt in range(self.max_retries):
                    try:
                        result = await asyncio.wait_for(
                            batter.play_defensive_shot_async(),
                            timeout=(self.timeout_ms * 2**attempt) / 1000.0
                        )
                        results.append(result)
                        break
                    except asyncio.TimeoutError:
                        if attempt == self.max_retries - 1:
                            # Escalate to higher-level strategy
                            results.append(
                                self._execute_fallback_strategy(batter_id)
                            )
                            self.batter_health[batter_id] = 'degraded'
            except Exception as e:
                # Log and recover without crashing orchestrator
                logger.error(f'Batter {batter_id} failed: {e}')
                results.append({'status': 'failed', 'reason': str(e)})
                self.batter_health[batter_id] = 'unhealthy'

        return self._aggregate_innings_results(results)

    def _execute_fallback_strategy(self, batter_id):
        return {'runs': 0, 'status': 'defensive', 'batter_id': batter_id}

    def _aggregate_innings_results(self, results):
        total_runs = sum(r.get('runs', 0) for r in results)
        health_report = self.batter_health
        return {'total_runs': total_runs, 'agent_health': health_report}
